func NewImage(f Format, proc *ImageProcessor, img image.Image, s Spec) *Image {
	if img != nil {
		return &Image{
			Format:	f,
			Proc:	proc,
			Spec:	s,
			imageConfig: &imageConfig{
				config:		imageConfigFromImage(img),
				configLoaded:	true,
			},
		}
	}
	return &Image{Format: f, Proc: proc, Spec: s, imageConfig: &imageConfig{}}
}
